postPopulate(field: FormlyFieldConfigCache) {
  if (field.parent) {
    return;
  }

  if (!field.options.checkExpressions) {
    let checkLocked = false;
    field.options.checkExpressions = (f, ignoreCache) => {
      if (checkLocked) {
        return;
      }

      checkLocked = true;
      const fieldChanged = this.checkExpressions(f, ignoreCache);
      const options = field.options;
      options._hiddenFieldsForCheck
        .sort((f) => (f.field.hide ? -1 : 1))
        .forEach((f) => this.changeHideState(f.field, f.field.hide ?? f.default, !ignoreCache));
      options._hiddenFieldsForCheck = [];
      if (fieldChanged) {
        this.checkExpressions(field);
      }
      checkLocked = false;
    };
  }
}

requestPassword(data?: any): Observable<NbAuthResult> {
  const module = 'requestPass';
  const method = this.getOption(`${module}.method`);
  const url = this.getActionEndpoint(module);
  return this.http.request(method, url, { body: data, observe: 'response', headers: this.getHeaders() }).pipe(
    map((res) => {
      if (this.getOption(`${module}.alwaysFail`)) {
        throw this.createFailResponse();
      }

      return res;
    }),
    map((res) => {
      return new NbAuthResult(
        true,
        res,
        this.getOption(`${module}.redirect.success`),
        [],
        this.getOption('messages.getter')(module, res, this.options),
      );
    }),
    catchError((res) => {
      return this.handleResponseError(res, module);
    }),
  );
}

export function createAction<T extends string, C extends Creator>(
  type: T,
  config?: { _as: 'props' } | C
): ActionCreator<T> {
  REGISTERED_ACTION_TYPES[type] = (REGISTERED_ACTION_TYPES[type] || 0) + 1;

  if (typeof config === 'function') {
    return defineType(type, (...args: any[]) => ({
      ...config(...args),
      type,
    }));
  }
  const as = config ? config._as : 'empty';
  switch (as) {
    case 'empty':
      return defineType(type, () => ({ type }));
    case 'props':
      return defineType(type, (props: object) => ({
        ...props,
        type,
      }));
    default:
      throw new Error('Unexpected config.');
  }
}

export function signalState<State extends object>(
  initialState: State
): SignalState<State> {
  const stateKeys = Reflect.ownKeys(initialState);

  const stateSource = stateKeys.reduce(
    (signalsDict, key) => ({
      ...signalsDict,
      [key]: signal((initialState as Record<string | symbol, unknown>)[key]),
    }),
    {} as SignalsDictionary
  );

  const signalState = computed(() =>
    stateKeys.reduce(
      (state, key) => ({ ...state, [key]: stateSource[key]() }),
      {}
    )
  );

  Object.defineProperty(signalState, STATE_SOURCE, {
    value: stateSource,
  });

  for (const key of stateKeys) {
    Object.defineProperty(signalState, key, {
      value: toDeepSignal(stateSource[key]),
    });
  }

  return signalState as SignalState<State>;
}

private triggerHook(name: keyof FormlyHookConfig, changes?: SimpleChanges) {
  if (name === 'onInit' || (name === 'onChanges' && changes.field && !changes.field.firstChange)) {
    this.valueChangesUnsubscribe();
    this.valueChangesUnsubscribe = this.fieldChanges(this.field);
  }

  if (this.field?.hooks?.[name]) {
    if (!changes || changes.field) {
      const r = this.field.hooks[name](this.field);
      if (isObservable(r) && ['onInit', 'afterContentInit', 'afterViewInit'].indexOf(name) !== -1) {
        const sub = r.subscribe();
        this.hooksObservers.push(() => sub.unsubscribe());
      }
    }
  }

  if (name === 'onChanges' && changes.field) {
    this.resetRefs(changes.field.previousValue);
    this.render();
  }
}

ngOnChanges() {
  const EXPR_VALIDATORS = FORMLY_VALIDATORS.map((v) => `templateOptions.${v}`);
  this.errorMessage$ = merge(
    this.field.formControl.statusChanges,
    !this.field.options
      ? of(null)
      : this.field.options.fieldChanges.pipe(
          filter(({ field, type, property }) => {
            return (
              field === this.field &&
              type === 'expressionChanges' &&
              (property.indexOf('validation') !== -1 || EXPR_VALIDATORS.indexOf(property) !== -1)
            );
          }),
        ),
  ).pipe(
    startWith(null),
    switchMap(() => (isObservable(this.errorMessage) ? this.errorMessage : of(this.errorMessage))),
  );
}

ngOnInit(): void {
  this._focusEl = document.activeElement;
  if (this.isAnimated) {
    this._renderer.addClass(
      this._element.nativeElement,
      CLASS_NAME.FADE
    );
  }
  this._renderer.setStyle(
    this._element.nativeElement,
    'display',
    'block'
  );
  setTimeout(() => {
    this.isShown = true;
    this._renderer.addClass(
      this._element.nativeElement,
      CLASS_NAME.SHOW
    );
  }, this.isAnimated ? TRANSITION_DURATIONS.BACKDROP : 0);
  if (document && document.body) {
    if (this.bsModalService && this.bsModalService.getModalsCount() === 1) {
      this.bsModalService.checkScrollbar();
      this.bsModalService.setScrollbar();
    }
    this._renderer.addClass(document.body, CLASS_NAME.OPEN);
    this._renderer.setStyle(document.body, 'overflow-y', 'hidden');
  }
  if (this._element.nativeElement) {
    this._element.nativeElement.focus();
  }
}

@HostListener('mousedown', ['$event'])
  onClickStarted(event: Event): void {
    if (!(event.target instanceof Element)) {
      this.clickStartedInContent = false;
      return;
    }
    this.clickStartedInContent = event.target !== this._element.nativeElement;
  }

  @HostListener('click', ['$event'])
  onClickStop(event: Event): void {
    if (!(event.target instanceof Element)) {
      this.clickStartedInContent = false;
      return;
    }
    const clickedInBackdrop = event.target === this._element.nativeElement && !this.clickStartedInContent;
    if (
      this.config.ignoreBackdropClick ||
      this.config.backdrop === 'static' ||
      !clickedInBackdrop
    ) {
      this.clickStartedInContent = false;

      return;
    }
    this.bsModalService?.setDismissReason(DISMISS_REASONS.BACKRDOP);
    this.hide();
  }

@HostListener('window:keydown.esc', ['$event'])
  onEsc(event: Event): void {
    if (!this.isShown) {
      return;
    }

    const keyboardEvent = event as KeyboardEvent;
    const hasKeyCode = (e: Event): e is KeyboardEvent & { keyCode: number } => 'keyCode' in e;
    const isEscape = keyboardEvent.key === 'Escape' || keyboardEvent.key === 'Esc' || (hasKeyCode(keyboardEvent) && keyboardEvent.keyCode === 27);
    if (!isEscape) {
      return;
    }

    keyboardEvent.preventDefault();

    if (
      this.config.keyboard &&
      this.level === this.bsModalService?.getModalsCount()
    ) {
      this.bsModalService?.setDismissReason(DISMISS_REASONS.ESC);
      this.hide();
    }
  }

onPopulate(field: F) {
  if (hasKey(field)) {
    const control = findControl(field);
    registerControl(field, control ? control : new UntypedFormArray([], { updateOn: field.modelOptions.updateOn }));
  }

  field.fieldGroup = field.fieldGroup || [];

  const length = Array.isArray(field.model) ? field.model.length : 0;
  if (field.fieldGroup.length > length) {
    for (let i = field.fieldGroup.length - 1; i >= length; --i) {
      unregisterControl(field.fieldGroup[i], true);
      field.fieldGroup.splice(i, 1);
    }
  }

  for (let i = field.fieldGroup.length; i < length; i++) {
    const f = { ...clone(typeof field.fieldArray === 'function' ? field.fieldArray(field) : field.fieldArray) };
    if (f.key !== null) {
      f.key = `${i}`;
    }

    field.fieldGroup.push(f);
  }
}

export function withMethods<
  Input extends SignalStoreFeatureResult,
  Methods extends MethodsDictionary,
>(
  methodsFactory: (
    store: Prettify<
      StateSignals<Input['state']> &
        Input['props'] &
        Input['methods'] &
        WritableStateSource<Input['state']>
    >
  ) => Methods
): SignalStoreFeature<Input, { state: {}; props: {}; methods: Methods }> {
  return (store) => {
    const methods = methodsFactory({
      [STATE_SOURCE]: store[STATE_SOURCE],
      ...store.stateSignals,
      ...store.props,
      ...store.methods,
    });
    if (typeof ngDevMode !== 'undefined' && ngDevMode) {
      assertUniqueStoreMembers(store, Reflect.ownKeys(methods));
    }

    return {
      ...store,
      methods: { ...store.methods, ...methods },
    } as InnerSignalStore<Record<string, unknown>, SignalsDictionary, Methods>;
  };
}

protected subscribeToEvents(windowRef: NbWindowRef) {
  if (windowRef.config.closeOnBackdropClick) {
    this.overlayRef.backdropClick().subscribe(() => windowRef.close());
  }

  if (windowRef.config.closeOnEsc) {
    this.overlayRef
      .keydownEvents()
      .pipe(filter((event: KeyboardEvent) => event.keyCode === 27))
      .subscribe(() => windowRef.close());
  }

  windowRef.stateChange.subscribe(() => this.checkAndUpdateOverlay());

  windowRef.onClose.subscribe(() => {
    this.openWindows.splice(this.openWindows.indexOf(windowRef), 1);
    this.checkAndUpdateOverlay();
  });
}

constructor() {
  // Clean-up all listeners and mark as destroyed upon destroy.
  this.destroyRef.onDestroy(() => {
    this.destroyed = true;
    this.listeners = null;
  });
}

subscribe(callback: (value: T) => void): OutputRefSubscription {
  if (this.destroyed) {
    throw new RuntimeError(
      RuntimeErrorCode.OUTPUT_REF_DESTROYED,
      ngDevMode &&
        'Unexpected subscription to destroyed `OutputRef`. ' +
          'The owning directive/component is destroyed.',
    );
  }

  (this.listeners ??= []).push(callback);

  return {
    unsubscribe: () => {
      const idx = this.listeners?.indexOf(callback);
      if (idx !== undefined && idx !== -1) {
        this.listeners?.splice(idx, 1);
      }
    },
  };
}

const escapes$ = fromEvent<KeyboardEvent>(document, 'keydown').pipe(
	takeUntil(closed$),
	filter((e) => e.key === 'Escape'),
	tap((e) => e.preventDefault()),
);

// we have to pre-calculate 'shouldCloseOnClick' on 'mousedown',
// because on 'mouseup' DOM nodes might be detached
const mouseDowns$ = fromEvent<MouseEvent>(document, 'mousedown').pipe(
	map(shouldCloseOnClick),
	takeUntil(closed$),
);

const closeableClicks$ = fromEvent<MouseEvent>(document, 'mouseup').pipe(
	withLatestFrom(mouseDowns$),
	filter(([_, shouldClose]) => shouldClose),
	delay(0),
	takeUntil(closed$),
) as Observable<MouseEvent>;

race([escapes$.pipe(map((_) => SOURCE.ESCAPE)), closeableClicks$.pipe(map((_) => SOURCE.CLICK))]).subscribe(
	(source: SOURCE) => zone.run(() => close(source)),
);

export function toDeepSignal<T>(signal: Signal<T>): DeepSignal<T> {
  return new Proxy(signal, {
    has(target: any, prop) {
      return !!this.get!(target, prop, undefined);
    },
    get(target: any, prop) {
      const value = untracked(target);
      if (!isRecord(value) || !(prop in value)) {
        if (isSignal(target[prop]) && (target[prop] as any)[DEEP_SIGNAL]) {
          delete target[prop];
        }

        return target[prop];
      }

      if (!isSignal(target[prop])) {
        Object.defineProperty(target, prop, {
          value: computed(() => target()[prop]),
          configurable: true,
        });
        target[prop][DEEP_SIGNAL] = true;
      }

      return toDeepSignal(target[prop]);
    },
  });
}

updateValue(value: string | number) {
    const currentValue = this.value();
    if (this.multiple()) {
        const newValue = Array.isArray(currentValue) ? [...currentValue] : [];
        const index = newValue.indexOf(value);

        if (index !== -1) {
            newValue.splice(index, 1);
        } else {
            newValue.push(value);
        }

        this.value.set(newValue as typeof this.value extends (...args: any) => infer R ? R : never);
    } else {
        if (currentValue === value) {
            this.value.set(undefined);
        } else {
            this.value.set(value);
        }
    }
}

scrollInView(index = -1) {
    const id = index !== -1 ? `${this.id}_${index}` : this.focusedOptionId;

    if (this.itemsViewChild && this.itemsViewChild.nativeElement) {
        const element = findSingle(this.itemsViewChild.nativeElement, `li[id="${id}"]`);
        if (element) {
            element.scrollIntoView && element.scrollIntoView({ block: 'nearest', inline: 'nearest' });
        } else if (!this.virtualScrollerDisabled) {
            setTimeout(() => {
                this.virtualScroll && this.scroller?.scrollToIndex(index !== -1 ? index : this.focusedOptionIndex());
            }, 0);
        }
    }
}

protected readonly pages = computed(() => {
  const pages: Page[] = [];
  let startPage = 1;
  let endPage = this.totalPages();
  const maxSize = 5;
  const isMaxSized = maxSize < this.totalPages();

  const page = this.page();

  if (isMaxSized) {
    startPage = page - Math.floor(maxSize / 2);
    endPage = page + Math.floor(maxSize / 2);

    if (startPage < 1) {
      startPage = 1;
      endPage = Math.min(startPage + maxSize - 1, this.totalPages());
    } else if (endPage > this.totalPages()) {
      startPage = Math.max(this.totalPages() - maxSize + 1, 1);
      endPage = this.totalPages();
    }
  }

  for (let num = startPage; num <= endPage; num++) {
    pages.push({
      number: num,
      text: num.toString()
    });
  }

  return pages;
});

function runOutsideAngular<T>(fn: (...args: any[]) => T): T {
  const ngZone = inject(NgZone, { optional: true });
  if (!ngZone) {return fn();}
  return ngZone.runOutsideAngular(() => fn());
}

function run<T>(fn: (...args: any[]) => T): T {
  const ngZone = inject(NgZone, { optional: true });
  if (!ngZone) {return fn();}
  return ngZone.run(() => fn());
}

const zoneWrapFn = (
  it: (...args: any[]) => any,
  taskDone: VoidFunction | undefined,
  injector: EnvironmentInjector,
) => {
  return (...args: any[]) => {
    if (taskDone) {
      setTimeout(taskDone, 0);
    }
    return runInInjectionContext(injector, () => run(() => it.apply(this, args)));
  };
};

constructor() {
	const ngZone = inject(NgZone);

	// Trap focus on active WindowCmpt
	this._activeWindowCmptHasChanged.subscribe(() => {
		if (this._windowCmpts.length) {
			const activeWindowCmpt = this._windowCmpts[this._windowCmpts.length - 1];
			ngbFocusTrap(ngZone, activeWindowCmpt.location.nativeElement, this._activeWindowCmptHasChanged);
			this._revertAriaHidden();
			this._setAriaHidden(activeWindowCmpt.location.nativeElement);
		}
	});
}

private _restoreScrollBar() {
	const scrollBarRestoreFn = this._scrollBarRestoreFn;
	if (scrollBarRestoreFn) {
		this._scrollBarRestoreFn = null;
		scrollBarRestoreFn();
	}
}

private _hideScrollBar() {
	if (!this._scrollBarRestoreFn) {
		this._scrollBarRestoreFn = this._scrollBar.hide();
	}
}

prePopulate(field: FormlyFieldConfigCache) {
  const root = field.parent;
  this.initRootOptions(field);
  this.initFieldProps(field);
  if (root) {
    Object.defineProperty(field, 'options', { get: () => root.options, configurable: true });
    Object.defineProperty(field, 'model', {
      get: () => (hasKey(field) && field.fieldGroup ? getFieldValue(field) : root.model),
      configurable: true,
    });
  }

  Object.defineProperty(field, 'get', {
    value: (key: FormlyFieldConfig['key']) => getField(field, key),
    configurable: true,
  });

  this.getFieldComponentInstance(field).prePopulate?.(field);
}

ngDoCheck() {
  if (!this.uiAttributes) {
    const element = this.elementRef.nativeElement as HTMLElement;
    this.uiAttributes = [...FORMLY_VALIDATORS, 'tabindex', 'placeholder', 'readonly', 'disabled', 'step'].filter(
      (attr) => !element.hasAttribute || !element.hasAttribute(attr),
    );
  }

  for (let i = 0; i < this.uiAttributes.length; i++) {
    const attr = this.uiAttributes[i];
    const value = this.props[attr];
    if (
      this.uiAttributesCache[attr] !== value &&
      (!this.props.attributes || !this.props.attributes.hasOwnProperty(attr.toLowerCase()))
    ) {
      this.uiAttributesCache[attr] = value;
      if (value || value === 0) {
        this.setAttribute(attr, this.getSafeAttributeValue(attr, value));
      } else {
        this.removeAttribute(attr);
      }
    }
  }
}

enter(value: number): void {
  if (!this.readonly()) {
    this.value = value;
    this.changeDetection.markForCheck();
    this.onHover.emit(value);
  }
}

reset(): void {
  if (typeof this.preValue === 'number') {
    this.value = Math.round(this.preValue);
    this.changeDetection.markForCheck();
    this.onLeave.emit(this.value);
  }
}

registerOnChange(fn: (_: number) => void): void {
  this.onChange = fn;
}

registerOnTouched(fn: () => void): void {
  this.onTouched = fn;
}

rate(value: number): void {
  if (!this.readonly() && this.range
    && value >= 0 && value <= this.range.length) {
    this.writeValue(value);
    this.onChange(value);
  }
}

animationRun(isAnimated: boolean, action: string) {
  if (!isAnimated || !this._stylesLoaded) {
    return (callback: () => void) => callback();
  }

  this._renderer.setStyle(this._el.nativeElement, 'overflow', 'hidden');
  this._renderer.addClass(this._el.nativeElement, 'collapse');

  const factoryAnimation = (action === this._EXPAND_ACTION_NAME)
    ? this._factoryExpandAnimation
    : this._factoryCollapseAnimation;

  if (this._player) {
    this._player.reset();
  }

  this._player = factoryAnimation.create(this._el.nativeElement);
  this._player.play();

  return (callback: () => void) => this._player?.onDone(callback);
}

validate(file: File): boolean {
    this.msgs = this.msgs || [];
    if (this.accept && !this.isFileTypeValid(file)) {
        const text = `${this.invalidFileTypeMessageSummary.replace('{0}', file.name)} ${this.invalidFileTypeMessageDetail.replace('{0}', this.accept)}`;
        this.msgs.push({
            severity: 'error',
            text: text
        });
        return false;
    }

    if (this.maxFileSize && file.size > this.maxFileSize) {
        const text = `${this.invalidFileSizeMessageSummary.replace('{0}', file.name)} ${this.invalidFileSizeMessageDetail.replace('{0}', this.formatSize(this.maxFileSize))}`;
        this.msgs.push({
            severity: 'error',
            text: text
        });
        return false;
    }

    return true;
}

override load(
  content: string,
  url: string,
): {locale: string; i18nNodesByMsgId: {[msgId: string]: i18n.Node[]}} {
  // xliff to xml nodes
  const xliffParser = new XliffParser();
  const {locale, msgIdToHtml, errors} = xliffParser.parse(content, url);

  // xml nodes to i18n nodes
  const i18nNodesByMsgId: {[msgId: string]: i18n.Node[]} = {};
  const converter = new XmlToI18n();

  Object.keys(msgIdToHtml).forEach((msgId) => {
    const {i18nNodes, errors: e} = converter.convert(msgIdToHtml[msgId], url);
    errors.push(...e);
    i18nNodesByMsgId[msgId] = i18nNodes;
  });

  if (errors.length) {
    throw new Error(`xliff parse errors:\n${errors.join('\n')}`);
  }

  return {locale: locale!, i18nNodesByMsgId};
}

