setAllNodesTabIndexes() {
    const nodes = <any>find(this.tree.el.nativeElement, '[data-pc-section="node"]');

    const hasSelectedNode = [...nodes].some((node) => node.getAttribute('aria-selected') === 'true' || node.getAttribute('aria-checked') === 'true');

    [...nodes].forEach((node) => {
        node.tabIndex = -1;
    });

    if (hasSelectedNode) {
        const selectedNodes = [...nodes].filter((node) => node.getAttribute('aria-selected') === 'true' || node.getAttribute('aria-checked') === 'true');

        selectedNodes[0].tabIndex = 0;

        return;
    }

    if (nodes.length) {
        ([...nodes][0] as any).tabIndex = 0;
    }
}

calcNewSorts(
  column: SortableTableColumnInternal,
  prevValue: SortDirection | undefined,
  newValue: SortDirection | undefined
): SortPropDir[] {
  let idx = 0;

  const sorts = this.sorts().map((s, i) => {
    s = { ...s };
    if (s.prop === column.prop) {
      idx = i;
    }
    return s;
  });

  if (newValue === undefined) {
    sorts.splice(idx, 1);
  } else if (prevValue) {
    sorts[idx].dir = newValue;
  } else {
    if (this.sortType() === 'single') {
      sorts.splice(0, this.sorts().length);
    }

    sorts.push({ dir: newValue, prop: column.prop });
  }

  return sorts;
}

onDragging(
  { currentX, currentY, initialX }: DragEvent,
  model: TableColumnInternal,
  element: HTMLElement
): void {
  if (!this.positions) {
    return;
  }
  const prevPos = this.positions[model.$$id];
  const target = this.isTarget(model, currentX, currentY);
  if (target) {
    if (this.lastDraggingIndex !== target.index) {
      this.targetChanged.emit({
        prevIndex: this.lastDraggingIndex!,
        newIndex: target.index,
        initialIndex: prevPos.index
      });
      this.lastDraggingIndex = target.index;
    }
  } else if (this.lastDraggingIndex !== prevPos.index) {
    this.targetChanged.emit({
      prevIndex: this.lastDraggingIndex!,
      initialIndex: prevPos.index
    });
    this.lastDraggingIndex = prevPos.index;
  }

  requestAnimationFrame(() => (element.style.left = `${currentX - initialX}px`));
}

export function d3InjectorTreeNodeModifier(d3Node: SvgD3Node<InjectorTreeNode>) {
  d3Node
    .attr('class', (node: InjectorTreeD3Node) => {
      return [d3Node.attr('class'), INJECTOR_TYPE_CLASS_MAP.get(node.data.injector.type) ?? '']
        .filter((c) => !!c)
        .join(' ');
    })
    .attr('hidden', (node: InjectorTreeD3Node) => (node.data.injector.id === 'N/A' ? 'true' : null))
    .attr('data-id', (node: InjectorTreeD3Node) => {
      return node.data.injector.id;
    })
    .attr('data-component-id', (node: InjectorTreeD3Node) => {
      if (node.data.injector.type === 'element') {
        const injector = node.data.injector;
        return injector.node?.component?.id ?? -1;
      }
      return -1;
    });
}

export const groupRowsByParents = <TRow extends Row>(
  rows: (TRow | undefined)[],
  from?: OptionalValueGetter,
  to?: OptionalValueGetter
): (TRow | undefined)[] => {
  if (from && to) {
    const treeRows = rows.filter(row => !!row).map(row => new TreeNode(row));
    const uniqIDs = new Map(treeRows.map(node => [to(node.row), node]));

    const rootNodes = treeRows.reduce((root, node) => {
      const fromValue = from(node.row);
      const parent = uniqIDs.get(fromValue);
      if (parent) {
        node.row.level = parent.row.level! + 1; // TODO: should be reflected by type, that level is defined
        node.parent = parent;
        parent.children.push(node);
      } else {
        node.row.level = 0;
        root.push(node);
      }
      return root;
    }, [] as TreeNode<TRow>[]);

    return rootNodes.flatMap(child => child.flatten());
  } else {
    return rows;
  }
};

export function observeDeep<T = any>(source: IObserveTarget<T>, paths: string[], setFn: () => void): () => void {
  let observers: (() => void)[] = [];

  const unsubscribe = () => {
    observers.forEach((observer) => observer());
    observers = [];
  };
  const observer = observe(source, paths, ({ firstChange, currentValue }) => {
    !firstChange && setFn();

    unsubscribe();
    if (isObject(currentValue) && currentValue.constructor.name === 'Object') {
      Object.keys(currentValue).forEach((prop) => {
        observers.push(observeDeep(source, [...paths, prop], setFn));
      });
    }
  });

  return () => {
    observer.unsubscribe();
    unsubscribe();
  };
}

export function getField(f: FormlyFieldConfig, key: FormlyFieldConfig['key']): FormlyFieldConfig {
  key = (Array.isArray(key) ? key.join('.') : key) as string;
  if (!f.fieldGroup) {
    return undefined;
  }

  for (let i = 0, len = f.fieldGroup.length; i < len; i++) {
    const c = f.fieldGroup[i];
    const k = (Array.isArray(c.key) ? c.key.join('.') : c.key) as string;
    if (k === key) {
      return c;
    }

    if (c.fieldGroup && (isNil(k) || key.indexOf(`${k}.`) === 0)) {
      const field = getField(c, isNil(k) ? key : key.slice(k.length + 1));
      if (field) {
        return field;
      }
    }
  }

  return undefined;
}

export async function generateZip(files: FileAndContent[]): Promise<Uint8Array> {
  if (zip === undefined || strToU8 === undefined) {
    const fflate = require('fflate');
    zip = fflate.zip;
    strToU8 = fflate.strToU8;
  }
  const filesObj: Record<string, Uint8Array> = {};
  files.forEach(({path, content}) => {
    filesObj[path] = typeof content === 'string' ? strToU8(content) : content;
  });

  return new Promise((resolve, reject) => {
    zip(filesObj, (err: any, data: any) => {
      if (err) {
        reject(err);
      } else {
        resolve(data);
      }
    });
  });
}

