getPrev(date: NgbDate, period: NgbPeriod = 'd', number = 1) {
	return this.getNext(date, period, -number);
}

getWeekday(date: NgbDate) {
	let jsDate = toJSDate(date);
	let day = jsDate.getDay();
	// in JS Date Sun=0, in ISO 8601 Sun=7
	return day === 0 ? 7 : day;
}

getWeekNumber(week: readonly NgbDate[], firstDayOfWeek: number) {
	// in JS Date Sun=0, in ISO 8601 Sun=7
	if (firstDayOfWeek === 7) {
		firstDayOfWeek = 0;
	}

	const thursdayIndex = (4 + 7 - firstDayOfWeek) % 7;
	let date = week[thursdayIndex];

	const jsDate = toJSDate(date);
	jsDate.setDate(jsDate.getDate() + 4 - (jsDate.getDay() || 7)); // Thursday
	const time = jsDate.getTime();
	jsDate.setMonth(0); // Compare with Jan 1
	jsDate.setDate(1);
	return Math.floor(Math.round((time - jsDate.getTime()) / 86400000) / 7) + 1;
}

export const expandToRow = <TRow extends Row>(
  targetRow: TRow,
  rows: (TRow | undefined)[],
  from?: OptionalValueGetter,
  to?: OptionalValueGetter
) => {
  if (from && to) {
    const uniqIDs = new Map(rows.filter(row => !!row).map(node => [to(node), node]));
    const visitedRowIds = new Set<unknown>();
    let currentRow: TRow | undefined = targetRow;

    while (currentRow) {
      const currentRowId = to(currentRow);
      if (visitedRowIds.has(currentRowId)) {
        // cycle detected, abort to avoid an infinite loop
        break;
      }
      visitedRowIds.add(currentRowId);

      if (currentRow.treeStatus === 'collapsed') {
        currentRow.treeStatus = 'expanded';
      }
      currentRow = uniqIDs.get(from(currentRow));
    }
  }
};

export function isDisabledDate(date?: Date, datesDisabled?: Date[], unit?: 'year' | 'date' | 'month'): boolean {
  if (!datesDisabled  || !isArray(datesDisabled) || !datesDisabled.length) {
    return false;
  }

  if (unit && unit === 'year' && !datesDisabled[0].getDate()) {
    return datesDisabled.some((dateDisabled: Date) => isSame(date, dateDisabled, 'year'));
  }

  return datesDisabled.some((dateDisabled: Date) => isSame(date, dateDisabled, 'date'));
}

export function isEnabledDate(date?: Date, datesEnabled?: Date[], unit?: 'year' | 'date' | 'month'): boolean {
  if (!datesEnabled || !isArray(datesEnabled) || !datesEnabled.length) {
    return false;
  }

  return !datesEnabled.some((enabledDate: Date) => isSame(date, enabledDate, unit || 'date'));
}

